  "local_paths": [
    "agent_tests"
  ],
  "public_task_contract": {
    "mode": "prose_only"
  },
  "sync_paths": [
    "components/controller/controller.c",
    "components/controller/include/controller.h",
    "components/protocol/protocol.c",
    "components/protocol/include/protocol.h",
